const t=JSON.parse(`{"key":"v-bfb60ae8","path":"/blog/article/22.html","title":"将 unity 嵌入 cocos（安卓）","lang":"zh-CN","frontmatter":{"title":"将 unity 嵌入 cocos（安卓）","date":"2023-03-21T16:25:00.000Z","category":["文章"],"tag":["CocosCreator","Unity","Android"],"description":"使用配置 unity 2021.3.20f1c1 cocos creator 3.6.1 ###备注： unity 打包依赖 sdk,ndk,il2cpp 需要提前使用 UnityHub 下载 接入步骤 导出 unity 安卓项目 将导出的 unity 安卓项目中的 unityLibrary 拷贝到 cocos 安卓项目根目录下 将 unity 安卓项目根目录\\\\launcher\\\\src\\\\main\\\\res 拷贝到 cocos项目根目录\\\\native\\\\engine\\\\android\\\\res，选择覆盖 将 cocos 安卓项目根目录\\\\unityLibrary\\\\libs\\\\unity-classes.jar 解压缩删除 com\\\\google 文件夹后再压缩为 unity-classes.jar settings.gradle 内增加 include，project('') build.gradle（Module）修改 build.gradle（Project）修改 在 cocos 安卓项目的 AndroidManifest 中修改 unityActivity 为单独进程，防止退出 unity 结束主进程 添加原生跳转方法 同步模块 ndk,sdk 版本设置","head":[["meta",{"property":"og:url","content":"https://muzzik.gitee.io/blog/article/22.html"}],["meta",{"property":"og:site_name","content":"MKSite"}],["meta",{"property":"og:title","content":"将 unity 嵌入 cocos（安卓）"}],["meta",{"property":"og:description","content":"使用配置 unity 2021.3.20f1c1 cocos creator 3.6.1 ###备注： unity 打包依赖 sdk,ndk,il2cpp 需要提前使用 UnityHub 下载 接入步骤 导出 unity 安卓项目 将导出的 unity 安卓项目中的 unityLibrary 拷贝到 cocos 安卓项目根目录下 将 unity 安卓项目根目录\\\\launcher\\\\src\\\\main\\\\res 拷贝到 cocos项目根目录\\\\native\\\\engine\\\\android\\\\res，选择覆盖 将 cocos 安卓项目根目录\\\\unityLibrary\\\\libs\\\\unity-classes.jar 解压缩删除 com\\\\google 文件夹后再压缩为 unity-classes.jar settings.gradle 内增加 include，project('') build.gradle（Module）修改 build.gradle（Project）修改 在 cocos 安卓项目的 AndroidManifest 中修改 unityActivity 为单独进程，防止退出 unity 结束主进程 添加原生跳转方法 同步模块 ndk,sdk 版本设置"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-09-14T09:20:42.000Z"}],["meta",{"property":"article:author","content":"muzzik"}],["meta",{"property":"article:tag","content":"CocosCreator"}],["meta",{"property":"article:tag","content":"Unity"}],["meta",{"property":"article:tag","content":"Android"}],["meta",{"property":"article:published_time","content":"2023-03-21T16:25:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-09-14T09:20:42.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"将 unity 嵌入 cocos（安卓）\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2023-03-21T16:25:00.000Z\\",\\"dateModified\\":\\"2023-09-14T09:20:42.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"muzzik\\"}]}"]]},"headers":[],"git":{"createdTime":1694672745000,"updatedTime":1694683242000,"contributors":[{"name":"yuanfengxin","email":"1226085293@qq.com","commits":3}]},"readingTime":{"minutes":1.75,"words":526},"filePathRelative":"blog/article/22.md","localizedDate":"2023年3月21日","excerpt":"<h1> 使用配置</h1>\\n<p>unity 2021.3.20f1c1<br>\\ncocos creator 3.6.1</p>\\n<p>###<strong>备注：</strong></p>\\n<ul>\\n<li>unity 打包依赖 sdk,ndk,il2cpp 需要提前使用 UnityHub 下载</li>\\n</ul>\\n<h1> 接入步骤</h1>\\n<ul>\\n<li>\\n<p>导出 unity 安卓项目<br>\\n<img src=\\"https://gitee.com/muzzik/images/raw/master/blog/article/22/1.png\\" alt=\\"\\" loading=\\"lazy\\"></p>\\n</li>\\n<li>\\n<p>将导出的 unity 安卓项目中的 unityLibrary 拷贝到 cocos 安卓项目根目录下</p>\\n</li>\\n<li>\\n<p>将 <code>unity 安卓项目根目录\\\\launcher\\\\src\\\\main\\\\res</code> 拷贝到 <code>cocos项目根目录\\\\native\\\\engine\\\\android\\\\res</code>，选择覆盖</p>\\n</li>\\n<li>\\n<p>将 <code>cocos 安卓项目根目录\\\\unityLibrary\\\\libs\\\\unity-classes.jar</code> 解压缩删除 <code>com\\\\google</code> 文件夹后再压缩为 unity-classes.jar</p>\\n</li>\\n<li>\\n<p>settings.gradle 内增加 include，project('')<br>\\n<img src=\\"https://gitee.com/muzzik/images/raw/master/blog/article/22/2.png\\" alt=\\"\\" loading=\\"lazy\\"></p>\\n</li>\\n<li>\\n<p>build.gradle（Module）修改<br>\\n<img src=\\"https://gitee.com/muzzik/images/raw/master/blog/article/22/3.png\\" alt=\\"\\" loading=\\"lazy\\"></p>\\n</li>\\n<li>\\n<p>build.gradle（Project）修改<br>\\n<img src=\\"https://gitee.com/muzzik/images/raw/master/blog/article/22/4.png\\" alt=\\"\\" loading=\\"lazy\\"></p>\\n</li>\\n<li>\\n<p>在 cocos 安卓项目的 AndroidManifest 中修改 unityActivity 为单独进程，防止退出 unity 结束主进程<br>\\n<img src=\\"https://gitee.com/muzzik/images/raw/master/blog/article/22/5.png\\" alt=\\"\\" loading=\\"lazy\\"></p>\\n</li>\\n<li>\\n<p>添加原生跳转方法<br>\\n<img src=\\"https://gitee.com/muzzik/images/raw/master/blog/article/22/6.png\\" alt=\\"\\" loading=\\"lazy\\"></p>\\n</li>\\n<li>\\n<p>同步模块 ndk,sdk 版本设置<br>\\n<img src=\\"https://gitee.com/muzzik/images/raw/master/blog/article/22/7.png\\" alt=\\"\\" loading=\\"lazy\\"></p>\\n</li>\\n</ul>","autoDesc":true}`);export{t as data};
